def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity == 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        if ratio > 2:
            priorities[i] = 2000 + 50 * (ratio - 2)**3
        elif ratio > 1:
            priorities[i] = 1500 + 20 * (ratio - 1)**2
        else:
            score = 0
            segment_scores = [0, 0, 0]
            for j in range(1, 6):
                if ratio > j * 0.1:
                    segment_scores[0] += 2 * j
                else:
                    break
            for j in range(5, 11):
                if capacity < j * 10:
                    segment_scores[1] += 3
                else:
                    segment_scores[2] += 1
            score = sum(segment_scores)
            if ratio > 0.9:
                score += 40
            elif ratio > 0.7:
                score += 25
            elif ratio > 0.4:
                score += 15
            if capacity < 5:
                score += 20
            elif capacity > 200:
                score -= 10
            if i % 2 == 1 and capacity % 2 == 1:
                score *= 0.7
            def is_prime(n):
                if n < 2:
                    return False
                for k in range(2, int(n ** 0.5) + 1):
                    if n % k == 0:
                        return False
                return True
            if is_prime(int(capacity)):
                score += 15
            priorities[i] = score
        if i % 3 == 0:
            priorities[i] *= 1.15
        elif i % 3 == 1:
            priorities[i] *= 0.85
        else:
            priorities[i] *= 1.05
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        min_priority = np.min(finite_priorities)
    else:
        min_priority = 0
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = min_priority + 200
    return priorities
